import React, { useEffect } from 'react';
import './Features.css';

const featureList = [
  {
    eyebrow: 'Emotion AI',
    title: '능동형 감정 케어',
    desc: '사용자가 먼저 요청하지 않아도 감정 흐름과 상황을 읽고 더 자연스럽게 반응합니다.',
    meta: '감정 변화 감지 · 선제적 대화',
    accentClass: 'blue',
  },
  {
    eyebrow: 'Insight Engine',
    title: '감정 패턴 인사이트',
    desc: '대화 기록과 흐름을 기반으로 감정 변화 패턴을 정리하고 회복 힌트를 제공합니다.',
    meta: '회고 · 루틴 제안 · 흐름 분석',
    accentClass: 'purple',
  },
  {
    eyebrow: 'Persona Design',
    title: 'AI 친구 커스터마이징',
    desc: '말투, 성향, 반응 강도를 조정해 나에게 가장 잘 맞는 AI 동반자를 만들 수 있습니다.',
    meta: '캐릭터 · 성격 · 톤 설정',
    accentClass: 'pink',
  },
  {
    eyebrow: 'Privacy First',
    title: '보안 중심 설계',
    desc: '감정 대화는 신뢰가 전부입니다. 메이티는 프라이버시를 핵심 원칙으로 설계합니다.',
    meta: '안심하고 이어지는 대화 경험',
    accentClass: 'mint',
  },
  {
    eyebrow: 'Always Available',
    title: '24시간 연결되는 경험',
    desc: '밤이든 새벽이든 감정을 나누고 싶을 때 끊김 없이 이어지는 대화를 제공합니다.',
    meta: '언제든 시작 가능한 AI 대화',
    accentClass: 'blue',
  },
  {
    eyebrow: 'Cross Platform',
    title: '웹 · 앱 동기화',
    desc: '웹과 데스크톱에서 시작한 대화가 자연스럽게 이어지도록 하나의 경험으로 연결됩니다.',
    meta: '연속성 있는 제품 경험',
    accentClass: 'purple',
  },
];

function Features() {
  useEffect(() => {
    const cards = document.querySelectorAll('.feature-card');

    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (!entry.isIntersecting) return;
          entry.target.classList.add('is-visible');
          observer.unobserve(entry.target);
        });
      },
      { threshold: 0.12 }
    );

    cards.forEach((card) => observer.observe(card));
    return () => observer.disconnect();
  }, []);

  return (
    <section className="features page-section" id="features">
      <div className="container">
        <div className="section-header">
          <div className="section-badge">핵심 기능</div>
          <h2 className="section-title">
            감성적인 경험과 제품 완성도를
            <br />
            <span className="gradient-text">함께 설계합니다</span>
          </h2>
          <p className="section-subtitle">
            따뜻함만으로는 부족하고, 기술만으로도 부족합니다.
            메이티는 인간적인 대화 경험과 세련된 AI 제품 구조를 동시에 제공합니다.
          </p>
        </div>

        <div className="features-grid">
          {featureList.map((feature, index) => (
            <article
              className={`feature-card reveal-up ${feature.accentClass}`}
              key={feature.title}
              style={{ transitionDelay: `${index * 70}ms` }}
            >
              <div className="feature-card-bg"></div>

              <div className="feature-top">
                <span className="feature-eyebrow">{feature.eyebrow}</span>
                <div className="feature-orb"></div>
              </div>

              <h3>{feature.title}</h3>
              <p>{feature.desc}</p>

              <div className="feature-bottom">
                <span className="feature-meta">{feature.meta}</span>
                <span className="feature-arrow">→</span>
              </div>
            </article>
          ))}
        </div>
      </div>
    </section>
  );
}

export default Features;
